(function() { const getTheme = () => { const stored = localStorage.getItem('theme'); if (stored) return stored; return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light'; }; const setTheme = (theme) => { document.documentElement.setAttribute('data-theme', theme); localStorage.setItem('theme', theme); const btn = document.getElementById('theme-toggle'); }; setTheme(getTheme()); window.addEventListener('DOMContentLoaded', () => { const btn = document.getElementById('theme-toggle'); if (btn) { btn.addEventListener('click', () => { const current = document.documentElement.getAttribute('data-theme'); setTheme(current === 'dark' ? 'light' : 'dark'); }); } const menuBtn = document.getElementById('menu-toggle'); const navLinks = document.querySelector('.nav-links'); if (menuBtn && navLinks) { menuBtn.addEventListener('click', () => { const isOpen = document.body.getAttribute('data-menu') === 'open'; document.body.setAttribute('data-menu', isOpen ? '' : 'open'); }); navLinks.querySelectorAll('a').forEach(link => { link.addEventListener('click', () => document.body.setAttribute('data-menu', '')); }); } }); })();